"use strict";(self.webpackChunkazurelocal_github_io=self.webpackChunkazurelocal_github_io||[]).push([[4203],{56766:e=>{e.exports=JSON.parse('{"tag":{"label":"os-configuration","permalink":"/docs/next/tags/os-configuration","allTagsPath":"/docs/next/tags","count":8,"items":[{"id":"implementation/04-cluster-deployment/phase-03-os-configuration/task-01-enable-winrm-for-remote-management","title":"Task 01: Enable WinRM for Remote Management","description":"Enable Windows Remote Management on all Azure Local nodes via iDRAC Virtual Console. Must run locally on each node \u2014 WinRM cannot be enabled remotely before it exists.","permalink":"/docs/next/implementation/04-cluster-deployment/phase-03-os-configuration/task-01-enable-winrm-for-remote-management"},{"id":"implementation/04-cluster-deployment/phase-03-os-configuration/task-02-enable-rdp","title":"Task 02: Enable RDP","description":"Enable Remote Desktop Protocol on all Azure Local nodes for graphical remote access during configuration and troubleshooting.","permalink":"/docs/next/implementation/04-cluster-deployment/phase-03-os-configuration/task-02-enable-rdp"},{"id":"implementation/04-cluster-deployment/phase-03-os-configuration/task-03-configure-static-ip-address","title":"Task 03: Configure Static IP Address","description":"Configure static IP addresses on the management network adapter for each Azure Local cluster node using explicit values from variables.yml.","permalink":"/docs/next/implementation/04-cluster-deployment/phase-03-os-configuration/task-03-configure-static-ip-address"},{"id":"implementation/04-cluster-deployment/phase-03-os-configuration/task-04-disable-dhcp-on-management-adapter","title":"Task 04: Disable DHCP on All Adapters","description":"Disable DHCP on all network adapters except virtual and management adapters to lock in static IP configuration across all Azure Local cluster nodes.","permalink":"/docs/next/implementation/04-cluster-deployment/phase-03-os-configuration/task-04-disable-dhcp-on-management-adapter"},{"id":"implementation/04-cluster-deployment/phase-03-os-configuration/task-05-configure-dns-servers","title":"Task 05: Configure DNS Servers","description":"Configure primary and secondary DNS server addresses on the management NIC of each Azure Local cluster node using explicit values from variables.yml.","permalink":"/docs/next/implementation/04-cluster-deployment/phase-03-os-configuration/task-05-configure-dns-servers"},{"id":"implementation/04-cluster-deployment/phase-03-os-configuration/task-06-verify-dns-client-configuration","title":"Task 06: Verify DNS Client Configuration","description":"Verify that DNS servers are correctly configured on the management NIC of each Azure Local node and that critical Azure endpoints resolve successfully.","permalink":"/docs/next/implementation/04-cluster-deployment/phase-03-os-configuration/task-06-verify-dns-client-configuration"},{"id":"implementation/04-cluster-deployment/phase-03-os-configuration/task-07-configure-time-synchronization-ntp","title":"Task 07: Configure Time Synchronization (NTP)","description":"Configure the NTP time source on each Azure Local node using w32tm \u2014 required for Kerberos authentication and AD domain operations.","permalink":"/docs/next/implementation/04-cluster-deployment/phase-03-os-configuration/task-07-configure-time-synchronization-ntp"},{"id":"implementation/04-cluster-deployment/phase-03-os-configuration/task-08-enable-icmp-ping","title":"Task 08: Enable ICMP (Ping)","description":"Enable ICMPv4 and ICMPv6 inbound firewall rules on each Azure Local node to allow ping for network diagnostics and connectivity validation.","permalink":"/docs/next/implementation/04-cluster-deployment/phase-03-os-configuration/task-08-enable-icmp-ping"}],"unlisted":false}}')}}]);